import{_ as i,o as t,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Update to Short Link Expiration Window","description":"","frontmatter":{"title":"Update to Short Link Expiration Window","slug":"updated-short-link-expiration-window"},"headers":[],"relativePath":"account-hub/updated-short-link-expiration-window.md","filePath":"account-hub/updated-short-link-expiration-window.md"}'),n={name:"account-hub/updated-short-link-expiration-window.md"};function o(s,e,l,d,c,p){return t(),a("div",null,[...e[0]||(e[0]=[r('<p>Branch Short Links will have a new expiration window in March 2024. Find out more in this update 🔗</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Effective March 11, 2024, all newly created Short Links will expire <strong>380 Days after creation</strong>.</p><div class="info custom-block"><p class="custom-block-title">Links Flagged for Expiration</p><p>If you have Branch Short Links that were flagged for expiration and have been deleted, reach out to your Branch Account Manager or <a href="./submit-a-ticket.html">Submit a Ticket</a> for backfill assistance until <strong>April 1, 2024</strong>.</p></div><p>There will be no changes to Long Links, Short Links, or Ad Links. By default, these links do not expire.</p><h3 id="expiration-window-reset" tabindex="-1">Expiration Window Reset <a class="header-anchor" href="#expiration-window-reset" aria-label="Permalink to &quot;Expiration Window Reset&quot;">​</a></h3><ul><li>For the Short Links that are already created and active, the expiration clocks on them will be reset.</li><li>When an existing Short Link is clicked or if Branch receives a <a href="./readexistingdeeplink.html">read request via the Deep Linking API</a>, the expiration window is reset to 380 days from the click/request.</li><li>To ensure a Short Link remains active forever, we recommend setting up a script to trigger a <a href="./deep-linking-api.html#read-existing-deep-link">GET request</a> periodically within the 380 Day timeframe.</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Looking to learn more about Branch Links in general including expiration behavior? View our guide here: <a href="./deep-linking-api.html#read-existing-deep-link">Create Deep Links</a></p></div>',8)])])}const k=i(n,[["render",o]]);export{u as __pageData,k as default};
